+  // icmp (BinOp X, C), X or icmp X, (BinOp X, C)
+  // where BinOp is sdiv, udiv, lshr, or ashr.
+  // For any constant C that guarantees the operation reduces the magnitude of X,
+  // the comparison can be simplified to a comparison of X with 0.
+  auto getDivOrShiftOp = [](BinaryOperator *&BO) -> unsigned {
+    if (!BO)
+      return Instruction::UserOp1;
+    switch (BO->getOpcode()) {
+    case Instruction::SDiv:
+    case Instruction::UDiv:
+    case Instruction::LShr:
+    case Instruction::AShr:
+      return BO->getOpcode();
+    default:
+      return Instruction::UserOp1;
+    }
+  };
+  unsigned Opcode;
+  BinaryOperator *DivOrShift = nullptr;
+  bool IsBO0 = false;
+  if ((Opcode = getDivOrShiftOp(BO0)) != Instruction::UserOp1 &&
+      Op1 == BO0->getOperand(0)) {
+    DivOrShift = BO0;
+    IsBO0 = true;
+  } else if ((Opcode = getDivOrShiftOp(BO1)) != Instruction::UserOp1 &&
+             Op0 == BO1->getOperand(0)) {
+    DivOrShift = BO1;
+    IsBO0 = false;
+  }
+  if (DivOrShift) {
+    const APInt *C;
+    if (match(DivOrShift->getOperand(1), m_APInt(C))) {
+      // Check that the divisor/shift amount is valid for the fold.
+      bool ValidShift = false;
+      if (Opcode == Instruction::SDiv) {
+        // Divisor must not be 0 (UB), 1 (X/1 == X), or -1 (overflow).
+        ValidShift = !C->isZero() && !C->isOne() && !C->isAllOnes();
+      } else if (Opcode == Instruction::UDiv) {
+        // Divisor must not be 0 (UB) or 1 (X/1 == X).
+        ValidShift = !C->isZero() && !C->isOne();
+      } else {
+        // LShr/AShr: shift amount must not be 0.
+        ValidShift = !C->isZero();
+      }
+      if (ValidShift) {
+        ICmpInst::Predicate EffectivePred =
+            IsBO0 ? Pred : ICmpInst::getSwappedPredicate(Pred);
+        // For ashr, only slt and sge are valid simplifications.
+        // For other operations, all signed predicates are valid.
+        if (Opcode != Instruction::AShr ||
+            EffectivePred == ICmpInst::ICMP_SLT ||
+            EffectivePred == ICmpInst::ICMP_SGE) {
+          ICmpInst::Predicate NewPred;
+          switch (EffectivePred) {
+          default:
+            NewPred = ICmpInst::BAD_ICMP_PREDICATE;
+            break;
+          case ICmpInst::ICMP_EQ:
+            if (Opcode == Instruction::AShr)
+              NewPred = ICmpInst::BAD_ICMP_PREDICATE;
+            else
+              NewPred = ICmpInst::ICMP_EQ;
+            break;
+          case ICmpInst::ICMP_NE:
+            if (Opcode == Instruction::AShr)
+              NewPred = ICmpInst::BAD_ICMP_PREDICATE;
+            else
+              NewPred = ICmpInst::ICMP_NE;
+            break;
+          case ICmpInst::ICMP_SLT:
+            NewPred = ICmpInst::ICMP_SGT;
+            break;
+          case ICmpInst::ICMP_SLE:
+            NewPred = ICmpInst::ICMP_SGE;
+            break;
+          case ICmpInst::ICMP_SGT:
+            NewPred = ICmpInst::ICMP_SLT;
+            break;
+          case ICmpInst::ICMP_SGE:
+            NewPred = ICmpInst::ICMP_SLE;
+            break;
+          }
+          if (NewPred != ICmpInst::BAD_ICMP_PREDICATE) {
+            Value *X = DivOrShift->getOperand(0);
+            return new ICmpInst(NewPred, X,
+                                Constant::getNullValue(X->getType()));
+          }
+        }
+      }
+    }
+  }
